using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using BenchmarkDotNet.Toolchains.CsProj;
using TextAnalysis;

var config = ManualConfig.Create(DefaultConfig.Instance)
    .AddJob(Job.Default.WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core90)
        .WithToolchain(CsProjCoreToolchain.NetCoreApp90))
    .AddJob(Job.Default.WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core100)
        .WithToolchain(CsProjCoreToolchain.NetCoreApp100));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog " +
        "A stitch in time saves nine " +
        "To be or not to be that is the question " +
        "All that glitters is not gold " +
        "The world is a stage and all the men and women merely players " +
        "It was the best of times it was the worst of times " +
        "Call me Ishmael Some years ago never mind how long precisely " +
        "In the beginning God created the heavens and the earth " +
        "It is a truth universally acknowledged that a single man in possession of a good fortune must be in want of a wife " +
        "Happy families are all alike every unhappy family is unhappy in its own way";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

